(function () {
  'use strict';
  const toggle = document.querySelector('.nav-toggle');
  const navList = document.querySelector('.nav-list');
  if (toggle && navList) {
    toggle.addEventListener('click', () => {
      const open = navList.classList.toggle('open');
      document.body.classList.toggle('menu-open', open);
      toggle.setAttribute('aria-expanded', open ? 'true' : 'false');
    });
    // Close on nav link click (mobile)
    navList.querySelectorAll('a').forEach(a => {
      a.addEventListener('click', () => {
        if (window.innerWidth <= 900) {
          navList.classList.remove('open');
          document.body.classList.remove('menu-open');
        }
      });
    });
    // Close on Escape key
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape' && navList.classList.contains('open')) {
        navList.classList.remove('open');
        document.body.classList.remove('menu-open');
        toggle.setAttribute('aria-expanded', 'false');
      }
    });
    // Close menu when window resizes back to desktop
    window.addEventListener('resize', () => {
      if (window.innerWidth > 900 && navList.classList.contains('open')) {
        navList.classList.remove('open');
        document.body.classList.remove('menu-open');
        toggle.setAttribute('aria-expanded', 'false');
      }
    });
  }
  (function highlightActive() {
    function normalize(str) {
      return (str || '')
        .toLowerCase()
        .replace(/\.html?$/, '')   // strip .html
        .replace(/\/$/, '')         // strip trailing slash
        .replace(/^\//, '')         // strip leading slash
        || 'home';                  // root path is "home"
    }
    const currentSlug = normalize(window.location.pathname);
    document.querySelectorAll('.nav-list a').forEach(a => {
      const linkSlug = normalize(a.getAttribute('href'));
      if (linkSlug === currentSlug) {
        a.classList.add('active');
      }
    });
  })();
  const reveals = document.querySelectorAll('.fade-up');
  if ('IntersectionObserver' in window && reveals.length) {
    // Mark body as animation-ready so CSS can hide .fade-up before reveal
    document.body.classList.add('anim-ready');
    // Safety fallback: after 3 seconds, force-reveal everything
    // in case any element never enters the viewport
    const fallbackTimer = setTimeout(() => {
      reveals.forEach(el => el.classList.add('in'));
    }, 3000);
    const io = new IntersectionObserver(entries => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          entry.target.classList.add('in');
          io.unobserve(entry.target);
        }
      });
    }, { threshold: 0.05, rootMargin: '0px 0px -40px 0px' });
    reveals.forEach(el => io.observe(el));
    // Once all are revealed, clear fallback timer
    window.addEventListener('load', () => {
      // After full page load, immediately reveal anything in viewport
      setTimeout(() => {
        reveals.forEach(el => {
          const rect = el.getBoundingClientRect();
          if (rect.top < window.innerHeight) el.classList.add('in');
        });
      }, 100);
    });
  }
  // If IntersectionObserver doesn't exist, content stays visible by default (no JS action needed)
  /* ---- FAQ — close others when one opens (optional UX) ---- */
  document.querySelectorAll('.faq-list').forEach(group => {
    const items = group.querySelectorAll('.faq-item');
    items.forEach(item => {
      item.addEventListener('toggle', () => {
        if (item.open) {
          items.forEach(other => { if (other !== item) other.open = false; });
        }
      });
    });
  });
  /* ---- Contact form — front-end only (mailto fallback + success feedback) ---- */
  const form = document.querySelector('#contact-form');
  if (form) {
    form.addEventListener('submit', (e) => {
      e.preventDefault();
      const name = form.querySelector('[name="name"]').value.trim();
      const email = form.querySelector('[name="email"]').value.trim();
      const subject = form.querySelector('[name="subject"]').value.trim() || 'Fishhear 咨询';
      const message = form.querySelector('[name="message"]').value.trim();
      if (!name || !email || !message) return;
      // Build a mailto fallback so the form works on static hosting
      const body = `From: ${name} <${email}>\n\n${message}`;
      const mailto = `mailto:hello@fishhear.example?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
      window.location.href = mailto;
      const success = form.querySelector('.form-success');
      if (success) {
        success.classList.add('show');
        setTimeout(() => success.classList.remove('show'), 6000);
      }
      form.reset();
    });
  }
  /* ---- Update copyright year ---- */
  document.querySelectorAll('[data-year]').forEach(el => {
    el.textContent = new Date().getFullYear();
  });
  /* ---- Back-to-top button ----
     Auto-injects the button into every page; shows after 400px of scroll;
     scrolls smoothly to top when clicked; hides automatically on mobile
     when the navigation menu is open. */
  (function backToTop() {
    // Skip if a button already exists (e.g. user added one manually)
    if (document.querySelector('.back-to-top')) return;
    const btn = document.createElement('button');
    btn.className = 'back-to-top';
    btn.setAttribute('aria-label', '回到顶部');
    btn.setAttribute('type', 'button');
    btn.innerHTML = `<svg viewBox="0 0 24 24" aria-hidden="true"><polyline points="18 15 12 9 6 15"></polyline></svg>`;
    document.body.appendChild(btn);
    const SHOW_AFTER = 400; // pixels of scroll before showing
    function update() {
      if (window.scrollY > SHOW_AFTER) {
        btn.classList.add('visible');
      } else {
        btn.classList.remove('visible');
      }
    }
    // Throttled scroll listener (rAF for performance)
    let ticking = false;
    window.addEventListener('scroll', () => {
      if (!ticking) {
        requestAnimationFrame(() => {
          update();
          ticking = false;
        });
        ticking = true;
      }
    }, { passive: true });
    btn.addEventListener('click', () => {
      // Smooth scroll if supported, instant fallback otherwise
      if ('scrollBehavior' in document.documentElement.style) {
        window.scrollTo({ top: 0, behavior: 'smooth' });
      } else {
        window.scrollTo(0, 0);
      }
    });
    // Initial check (in case page loads scrolled)
    update();
  })();
  /* ---- Floating social stack ----
     Auto-injects vertical social icon column on the right edge.
     Above the back-to-top button. Toggleable open/closed. */
  (function floatingSocials() {
    if (document.querySelector('.float-socials')) return;
    const platforms = [
      { name: 'Pinterest', href: 'https://www.pinterest.com/', color: '#E60023', icon: '<path d="M12 0C5.4 0 0 5.4 0 12c0 5 3.1 9.4 7.6 11.2-.1-.95-.2-2.4 0-3.45.2-.95 1.3-6 1.3-6s-.3-.7-.3-1.7c0-1.6.95-2.8 2.1-2.8 1 0 1.5.75 1.5 1.65 0 1-.6 2.5-1 3.9-.3 1.15.6 2.1 1.7 2.1 2.1 0 3.7-2.2 3.7-5.4 0-2.8-2-4.8-4.9-4.8-3.3 0-5.3 2.5-5.3 5.1 0 1 .4 2.1.9 2.7.1.1.1.2.1.3-.1.4-.3 1.15-.3 1.3-.05.2-.2.3-.4.15-1.4-.7-2.3-2.7-2.3-4.4 0-3.6 2.6-6.9 7.5-6.9 3.95 0 7 2.8 7 6.55 0 3.9-2.45 7.05-5.9 7.05-1.15 0-2.25-.6-2.6-1.3 0 0-.6 2.2-.7 2.75-.25 1-1 2.3-1.5 3.05A12 12 0 0 0 24 12C24 5.4 18.6 0 12 0z"/>' },
      { name: 'Medium', href: 'https://medium.com/', color: '#000000', icon: '<path d="M13.54 12a6.8 6.8 0 0 1-6.77 6.82A6.8 6.8 0 0 1 0 12a6.8 6.8 0 0 1 6.77-6.82A6.8 6.8 0 0 1 13.54 12zM20.96 12c0 3.54-1.51 6.42-3.38 6.42-1.87 0-3.39-2.88-3.39-6.42s1.52-6.42 3.39-6.42 3.38 2.88 3.38 6.42M24 12c0 3.17-.53 5.75-1.19 5.75-.66 0-1.19-2.58-1.19-5.75s.53-5.75 1.19-5.75C23.47 6.25 24 8.83 24 12z"/>' },
      { name: 'Quora', href: 'https://www.quora.com/', color: '#B92B27', icon: '<path d="M12.738 18.701c-.831-1.635-1.805-3.27-3.72-3.27-.366 0-.733.061-1.038.183l-.671-1.34c.793-.671 2.073-1.22 3.72-1.22 2.561 0 3.844 1.22 4.86 2.806.612-1.342.916-3.111.916-5.247 0-5.371-1.689-8.117-5.066-8.117-3.314 0-5 2.746-5 8.117 0 5.31 1.686 8.041 5 8.041.394 0 .732-.031 1.041-.092zm1.099 2.107c.917.182 1.711.243 2.318.243 3.197 0 4.665-1.83 4.665-3.945h-1.345c-.244 1.4-1.099 1.91-2.135 1.91-.732 0-1.404-.244-2.014-.55C19.305 16.811 22 13.624 22 9.413 22 4.318 18.014 1 12.84 1 7.736 1 3.689 4.318 3.689 9.413c0 4.943 4.046 8.318 9.151 8.318h.366c.245 1.16.917 2.32 1.831 3.077z"/>' },
      { name: 'Reddit', href: 'https://www.reddit.com/', color: '#FF4500', icon: '<path d="M12 0A12 12 0 0 0 0 12a12 12 0 0 0 12 12 12 12 0 0 0 12-12A12 12 0 0 0 12 0zm5.01 4.744c.688 0 1.25.561 1.25 1.249a1.25 1.25 0 0 1-2.498.056l-2.597-.547-.8 3.747c1.824.07 3.48.632 4.674 1.488.308-.309.73-.491 1.207-.491.968 0 1.754.786 1.754 1.754 0 .716-.435 1.333-1.01 1.614a3.111 3.111 0 0 1 .042.52c0 2.694-3.13 4.87-7.004 4.87-3.874 0-7.004-2.176-7.004-4.87 0-.183.015-.366.043-.534A1.748 1.748 0 0 1 4.028 12c0-.968.786-1.754 1.754-1.754.463 0 .898.196 1.207.49 1.207-.883 2.878-1.43 4.744-1.487l.885-4.182a.342.342 0 0 1 .14-.197.35.35 0 0 1 .238-.042l2.906.617a1.214 1.214 0 0 1 1.108-.701zM9.25 12C8.561 12 8 12.562 8 13.25c0 .687.561 1.248 1.25 1.248.687 0 1.248-.561 1.248-1.249 0-.688-.561-1.249-1.249-1.249zm5.5 0c-.687 0-1.248.561-1.248 1.25 0 .687.561 1.248 1.249 1.248.688 0 1.249-.561 1.249-1.249 0-.687-.562-1.249-1.25-1.249zm-5.466 3.99a.327.327 0 0 0-.231.094.33.33 0 0 0 0 .463c.842.842 2.484.913 2.961.913.477 0 2.105-.056 2.961-.913a.361.361 0 0 0 .029-.463.33.33 0 0 0-.464 0c-.547.533-1.684.73-2.512.73-.828 0-1.979-.196-2.512-.73a.326.326 0 0 0-.232-.095z"/>' }
    ];
    const wrap = document.createElement('div');
    wrap.className = 'float-socials';
    wrap.setAttribute('aria-label', '在社交媒体关注 Fishhear');
    platforms.forEach(p => {
      const a = document.createElement('a');
      a.href = p.href;
      a.target = '_blank';
      a.rel = 'noopener noreferrer';
      a.className = 'float-social';
      a.setAttribute('aria-label', `Follow Fishhear on ${p.name}`);
      a.style.setProperty('--brand', p.color);
      a.innerHTML = `<svg viewBox="0 0 24 24" fill="currentColor" aria-hidden="true">${p.icon}</svg>`;
      wrap.appendChild(a);
    });
    document.body.appendChild(wrap);
  })();
})();